---@param battleUnit LFightUnit
function LFightEffect:LFightEffect(battleUnit,parentTrans,effectName,pos,dir)
	self._battleUnit = battleUnit
	--父节点
	self._parentTrans = parentTrans
	--资源名字
	self._effectName = effectName
	--资源类型 1，特效；2，spine
	self._effectType = LFightEffect.EFFECT

	--开始播放时间
	self._startTime = 0
	--持续时间
	self._playTime = 0

	----显示对象
	--self._dp = nil
	----预加载的对象
	--self._pdp = nil

	--是否正在播放
	self._isPlaying = false
	----已经加载完成
	--self._isPreloaded = false

	--光效管理器创建的id
	self._index = 0

	self._pos = pos

	self._dir = dir or LFightConst.DIRECTION_RIGHT

	self._upperLayer = false

	-- 拥有缩放的弹道类型
	self._scaleType =
	{
		[LSkillEffConst.BULLET_LINEAR_THREE] = true,
		[LSkillEffConst.BULLET_NOANGLE_LINEAR_THREE] = true,
	}


	self._effectState = LFightEffect.STATE_NONE

	self._createType = LFightEffect.NORMAL

	---@type LFightObject 特效bone作用对象 或 buff 添加对象
	self._targetObj = nil

	---@type string bone
	self._boneName = nil

	self._effData = nil

	---@type boolean 是否持久化
	self._isPersistence = false

	self._isBattleSkill = false

	self._extraData = nil
end


function LFightEffect:Create(idx,parentTrans,effId,pos,dir,startTime,playTime,dissipateTime,isLongCache,resType)
	self._index = idx
	self._parentTrans = parentTrans

	if pos then
		pos = pos:Clone()
	else
		pos = Vector3(0,0,0)
	end
	self._pos = pos

	self._dir = dir

	self._effectName = effId

	self._startTime = self._battleUnit:GetTime() + startTime

	self._playTime = self._startTime + playTime

	self._dissipateTime = self._playTime + dissipateTime

	self._effectType = resType or LFightEffect.EFFECT

	if isLongCache then
		self._isLongCache = isLongCache
	end
end


function LFightEffect:SetEffectPara(para)
	self._type = para.type
	self._upperLayer = para.isUpperLayer or false
	self._scale = para.scale or 1

	self._skillId = para.skillId

	self._skin = para.skin

	self._order = para.order

	self._localPos = para.localPos

	self._onStartCall = para.onStartCall

	self._onEndCall = para.onEndCall

	self._targetObj = para.targetObj

	self._boneName = para.boneName

	self._createType = LFightEffect.NORMAL

	self._buffId = para.buffId

	self._isPersistence = para.isPersistence or false

	self._buffEffShowType = para.buffEffShowType or -1

	self._extraData = para.extraData
end

function LFightEffect:SetBattleSkillEffect(isBattleSkill)
	self._isBattleSkill = isBattleSkill
end

function LFightEffect:GetIsBattleSkill()
	return self._isBattleSkill
end

