function LFightEffect:SetBullet(isBullet,bulletTarPos,bulletFlyTime,bulletTrack,index)
	self._isBullet = isBullet
	self._bulletTarPos = bulletTarPos
	self._bulletFlyTime = bulletFlyTime
	self._bulletTrack = bulletTrack or 0
	self._bulletIndex = index -- 第几颗子弹
end

function LFightEffect:SetBeforePlay(dp)
	self:InitEffect()

	local showState = true
	if not self._isBattleSkill then
		local effectCtrl = self._battleUnit:GetEffectCtrl()
		if effectCtrl and effectCtrl:CheckIsShowEffectFocus() then
			local targetObj = self._targetObj
			if targetObj and not effectCtrl:CheckIsHurtHero(targetObj) then
				showState = false
				effectCtrl:AddRecordHideEffectList(self)
			end
		end
	end
	dp:SetVisible(showState) --skeletonAnimation 的 AnimationState 需要在Unity.Start之后

	dp:ResetPlayState()

	local dpTrans = dp:GetDisplayTrans()

	local extraData = self._extraData
	if extraData then
		local type = extraData.type
		local serData = extraData.serData
		if type == LFightConst.BUFF_SPECIAL_1 then
			local pointTrans = CS.FindTrans(dpTrans,extraData.rootPath)
			local Icon = CS.FindTrans(pointTrans,"Icon")
			self:SetXTextContent(CS.FindTrans(pointTrans,"LVText"),string.replace("LV.#a1#",serData.level))
			self:SetXTextContent(CS.FindTrans(pointTrans,"NameText"),serData.name)
			self:SetSpriteRenderer(Icon, serData.icon, function()
				CS.ShowObject(pointTrans,true)
			end)
		end

	end

	local layer,order
	local rendererList = dp:GetRendererList() or {}
	local rendererLen = #rendererList
	local rendererLayerList = dp:GetRendererLayerList() or {}
	local rendererOrderList = dp:GetRendererOrderList() or {}
	for k = 1, rendererLen do
		local renderer = rendererList[k]
		layer = rendererLayerList[k]
		order = rendererOrderList[k]
		if not layer then
			layer = renderer.sortingLayerName
		end

		if not order then
			order = renderer.sortingOrder
		end

		if self._upperLayer then
			layer = LFightLayerConst.toUpperLayer[layer] or layer
		else
			layer = LFightLayerConst.toLowerLayer[layer] or layer
		end
		renderer.sortingLayerName = layer
		if layer == "Object" and self._order then
			renderer.sortingOrder = self._order + order
		end

	end

	self:SetSkillInfo(dpTrans)
end

function LFightEffect:ResetRenderOrder(order)
	if not order then
		return
	end

	local dp = self._loadDp
	if not dp or not dp:IsDpValid() then
		return
	end

	local _order
	local rendererList = dp:GetRendererList() or {}
	local rendererLen = #rendererList
	local _rendererOrderList = dp:GetRendererOrderList() or {}
	for k = 1, rendererLen do
		local renderer = rendererList[k]
		_order = _rendererOrderList[k]

		if not _order then
			_order = renderer.sortingOrder
		end

		if renderer.sortingLayerName == "Object" then
			renderer.sortingOrder = _order + order
		end
	end

end


