function LFightEffect:PlayEffect()
	local state = self._effectState
	self._isPlaying = true
	if state == LFightEffect.STATE_NONE then
		self:LoadEffectImpl(self._index,self._parentTrans,self._effectName,self._effectType)
	elseif state == LFightEffect.STATE_LOADED then
		self:StartPlay()
	end
end




function LFightEffect:CalcCurvePos(traceType,tarPos,bulletTarPos)
	if(traceType == 1) then
		return self:CalcCurvePosOne(tarPos,bulletTarPos)
	elseif(traceType == 2) then
		return self:CalcCurvePosTwo(tarPos,bulletTarPos)
	end
	return tarPos,bulletTarPos
end

function LFightEffect:CalcCurvePosOne(tarPos,bulletTarPos)
	local topPosX = Mathf.Lerp(tarPos.x , bulletTarPos.x,  2 / 3)
	local topPosY = Mathf.Lerp(tarPos.y , bulletTarPos.y,  0.5)
	local offectY = Vector3.Distance(tarPos, bulletTarPos)
	local topPos = Vector3(topPosX,topPosY + offectY,0)
	return topPos,bulletTarPos
end

function LFightEffect:CalcCurvePosTwo(tarPos,bulletTarPos)
	local topPosX = Mathf.Lerp(tarPos.x , bulletTarPos.x,  1 / 2)
	local topPosY = Mathf.Lerp(tarPos.y , bulletTarPos.y,  0.5)
	local offectY
	local isUp = self._bulletIndex % 2 == 1
	if isUp then
		offectY = math.random(0,15) * 0.1
	else
		offectY = math.random(-15,0) * 0.1
	end

	local topPos = Vector3(topPosX,topPosY + offectY,0)

	return topPos,bulletTarPos
end

function LFightEffect:SetPosition(pos)
	if not self._loadDp then
		return
	end
	if not self._loadDp:IsDpValid() then
		return
	end
	local dpTrans = self._loadDp:GetDisplayTrans()
	dpTrans.position = Vector3(pos.x,pos.y,pos.y * 0.01)
end

function LFightEffect:Destroy()
	if self._isDestroy then
		return
	end

	if self._loadDp then
		self._loadDp:Destroy()
		self._loadDp = nil
	end

	LxNodeBase.Dispose(self)
	self._isDestroy = true
end

function LFightEffect:IsDestroy()
	return self._isDestroy
end
-----------------------------------------------------------------
function LFightEffect:OnRun(time)
	if self._isDestroy then return false end

	if not self._isPlaying then
		if self._startTime <= time then
			self:PlayEffect()
		end
	else
		if not self._isPersistence then
			if self._dissipateTime < time  then
				if self._onEndCall then
					self._onEndCall()
					self._onEndCall = nil
				end
				return false
			end
		end
	end
	return true
end

function LFightEffect:GetIndex()
	return self._index
end

function LFightEffect:GetEffId()
	return self._effectName
end

function LFightEffect:IsLongCache()
	return self._isLongCache
end

function LFightEffect:SetVisible(isVisible)
	if self._loadDp then
		self._loadDp:SetVisible(isVisible)
	end
end

function LFightEffect:ResetToPreloaded()
	self._isPlaying = false
	self._effectState = LFightEffect.STATE_LOADED
	local dp = self._loadDp
	dp:SetVisible(false)
	if self._effectType == LFightEffect.SPINE then
		return
	end

	if not self._isInit then
		return
	end

	dp:ClearOldPlayState()
end



