---整理战斗特效加载接口
function LFightEffect:LoadEffectImpl(idx,root,resName,resType,endFunc)
	resType = resType or 1

	if self._effectState > LFightEffect.STATE_NONE then
		return
	end

	self._effectState = LFightEffect.STATE_LOADING

	local dp,isSuc
	if resType == LFightEffect.SPINE then
		dp = LDisplaySpine:New()
	else
		dp = LDisplayEffect:New()
	end

	self._loadDp = dp

	isSuc = dp:CreateImpl(root,resName)
	dp:SetResTag(CS.RES_TAG_SCENE)
	dp:SetLoadedFunction(function()
		self:OnCheckNeedAddBone(resType)
		self:OnEffectLoadSuc()
		if endFunc then
			endFunc(idx)
		end
	end)
	dp:SetLoadFailFunc(function()
		self._effectState = LFightEffect.STATE_NONE
		if endFunc then
			endFunc(idx)
		end
	end)
	dp:StartLoad()

	return isSuc
end

function LFightEffect:OnCheckNeedAddBone(resType)
	if resType == LFightEffect.SPINE then return end
	if self._createType == LFightEffect.NORMAL then
		self:CheckNormalIsNeedAddBone()
	elseif self._createType == LFightEffect.PRELOAD then
		self:CheckPreloadIsNeedAddBone()
	end
end

function LFightEffect:CheckNormalIsNeedAddBone()
	if not self._loadDp then return end

	if not self._targetObj or string.isempty(self._boneName) then return end

	local spineDp = self._targetObj:GetDisplayObj()
	if not spineDp then return end

	---@type LDisplayEffect
	local loadDp = self._loadDp
	loadDp:InternalInitBoneFollower(spineDp,self._boneName)
end

function LFightEffect:CheckPreloadIsNeedAddBone()
	if not self._loadDp then return end

	if not self._targetObj or string.isempty(self._boneName) then return end

	local spineDp = self._targetObj:GetDisplayObj()
	if not spineDp then return end

	---@type LDisplayEffect
	local loadDp = self._loadDp
	loadDp:InternalInitBoneFollower(spineDp,self._boneName)
end

