---预加载资源使用
function LFightEffect:PreloadCreate(idx,root,resName,resType,endFunc,isLongCache)
	self._index = idx
	self._parentTrans = root
	self._effectName = resName
	self._effectType = resType or LFightEffect.EFFECT
	self._isLongCache = isLongCache
	self._createType = LFightEffect.PRELOAD
	return self:LoadEffectImpl(self._index,self._parentTrans,self._effectName,self._effectType,endFunc)
end

function LFightEffect:SetEffData(effData)
	if not effData then return end
	self._effData = effData
	self._boneName = effData.boneName
end

function LFightEffect:SetTargetObj(targetObj)
	if not targetObj then return end
	self._targetObj = targetObj
end

function LFightEffect:OnEffectLoadSuc()
	self._effectState = LFightEffect.STATE_LOADED
	if self._loadDp then
		self._loadDp:SetVisible(false)
	end
	if self._isPlaying then
		self:StartPlay()
	end
end

function LFightEffect:GetEffectPlayState()
	return self._isPlaying
end

function LFightEffect:CheckTargetObjDead()
	return self._targetObj and self._targetObj:IsDead()
end

function LFightEffect:GetTargetObjId()
	return self._targetObj and self._targetObj:GetId()
end

function LFightEffect:CheckIsAtkObjHitEffect(atkObjId)
	if not atkObjId then return false end
	local targetId = self:GetTargetObjId()
	if not targetId then return false end
	return targetId == atkObjId and self:CheckIsHitShowBuff()
end

function LFightEffect:CheckIsBuffEffShowReplace()
	local buffEffShowType = self._buffEffShowType or -1
	return buffEffShowType == ModelSkill.TYPE_BUFFEFFSHOWTIME_REPLACE
end

function LFightEffect:CheckIsHitShowBuff()
	if not self._buffId or self._buffId < 1 then return false end
	return gModelSkill:CheckIsHitShowBuff(self._buffId)
end

function LFightEffect:InitEffect()
	if not self._loadDp then
		return
	end
	if self._isInit then
		return
	end
	self._isInit = true

	local dp = self._loadDp
	dp:SetVisible(false)
	if self._effectType == LFightEffect.SPINE then
		return
	end

	dp:InitRendererInfo()

end

function LFightEffect:StartPlay()

	if self._onStartCall then
		self._onStartCall()
		self._onStartCall = nil
	end

	self._effectState = LFightEffect.STATE_PLAYING

	local resType = self._effectType or LFightEffect.EFFECT
	if resType == LFightEffect.EFFECT then
		self:StartPlay_Effect()
		self:OnCheckNeedAddBone(resType)
	else
		self:StartPlay_Spine()
	end



end

function LFightEffect:StartPlay_Spine()
	local dp = self._loadDp
	if not dp:IsDpValid() then
		return
	end
	if dp:GetParentTrans() ~= self._parentTrans then
		dp:SetParentTrans(self._parentTrans)
	end

	local dpTrans = dp:GetDisplayTrans()

	if self._pos then
		dpTrans.position = Vector3(self._pos.x,self._pos.y,self._pos.y * 0.01)
	end
	if self._localPos then
		dpTrans.localPosition = self._localPos
	end

	local scale = self._scale or 1
	dpTrans.localScale = Vector3.one * scale

	dp:SetVisible(true)

	local layer = "EffectDown"
	if self._upperLayer then
		layer = "EffectUp"
	end

	dp:SetRenderLayer(layer)

	dp:PlayAnimation(0,"show",false)
end

function LFightEffect:StartPlay_Effect()
	local dp = self._loadDp


	if not dp:IsDpValid() then
		return
	end

	if dp:GetParentTrans() ~= self._parentTrans then
		dp:SetParentTrans(self._parentTrans)
	end
	local dpTrans = dp:GetDisplayTrans()

	if self._pos then
		--dpTrans.position = Vector3(self._pos.x,self._pos.y,self._pos.y * 0.01)
		local posZ = self._pos.z > 0 and self._pos.z or self._pos.y * 0.01
		dpTrans.position = Vector3(self._pos.x,self._pos.y,posZ)
	end

	if self._localPos then
		dpTrans.localPosition = self._localPos
	end

	local scale = self._scale or 1
	dpTrans.localScale = Vector3.one * scale

	local dir = self._dir
	if dir == LFightConst.DIRECTION_RIGHT then
		dpTrans.localEulerAngles = Vector3(0,0,0)
	else
		dpTrans.localEulerAngles = Vector3(0,180,0)
	end


	--子弹
	if self._isBullet then
		local comp = dpTrans:GetComponent(typeofBtObjectView)
		if not comp then
			comp = dpTrans.gameObject:AddComponent(typeofBtObjectView)
		end
		local time = self._battleUnit:GetTime()
		local calcTime = time - self._startTime
		local flyTime = self._bulletFlyTime
		local bulletTarPos = self._bulletTarPos
		local bulletTrack = self._bulletTrack
		if bulletTrack >= 100 then --100以上是不带z旋转的
			comp:EnableAngle(false)
		else
			comp:EnableAngle(true)
		end

		if self._scaleType[bulletTrack] then
			comp:EnableScale(true,2.4)
		end

		if bulletTrack == LSkillEffConst.BULLET_LINEAR or bulletTrack == LSkillEffConst.BULLET_NOANGLE_LINEAR or
				bulletTrack == LSkillEffConst.BULLET_LINEAR_THREE or bulletTrack == LSkillEffConst.BULLET_NOANGLE_LINEAR_THREE then
			comp:StartMove(bulletTarPos,flyTime,calcTime)
		else
			local traceType
			if bulletTrack == LSkillEffConst.BULLET_CURVE_ONE or bulletTrack == LSkillEffConst.BULLET_NOANGLE_CURVE_ONE then
				traceType = 1
			elseif bulletTrack == LSkillEffConst.BULLET_CURVE_TWO or bulletTrack == LSkillEffConst.BULLET_NOANGLE_CURVE_TWO then
				traceType = 2
			end

			local tarPos = dpTrans.position
			local topPos,bulletTarPos = self:CalcCurvePos(traceType,tarPos,bulletTarPos)
			comp:StartJump(bulletTarPos, topPos, flyTime, calcTime)

			if calcTime > 0 then
				--为了让角度平滑 过度，预演 前一帧位置
				local t = 1
				if flyTime > 0 then t = calcTime / flyTime end
				t = t - 0.03
				if t < 0 then t = 0 end
				dpTrans.position = comp:GetPoint(t)
			end
		end

		comp:UpdatePos()
	end

	self:SetBeforePlay(dp)
end

--- 修改持久化状态
function LFightEffect:SetPersistenceStatus(status)
	self._isPersistence = status
end
-----------------------------------------------------------------
return LFightEffect
